CREATE TABLE transfer_jobs (job_id VARCHAR(36) NOT NULL, created_by VARCHAR(64) NOT NULL, model_snapshot JSON NOT NULL, request_snapshot JSON NOT NULL, source_object_key VARCHAR(512) NULL, result_object_key VARCHAR(512) NULL, error_object_key VARCHAR(512) NULL, committed_at DATETIME(6) NULL, errors_truncated BOOLEAN NOT NULL DEFAULT FALSE, request_method VARCHAR(8) CHARACTER SET ascii COLLATE ascii_bin NOT NULL, request_path VARCHAR(512) CHARACTER SET ascii COLLATE ascii_bin NOT NULL, idempotency_key VARCHAR(128) CHARACTER SET ascii COLLATE ascii_bin NOT NULL, request_hash CHAR(64) CHARACTER SET ascii COLLATE ascii_bin NOT NULL, idempotency_expires_at DATETIME(6) NOT NULL, PRIMARY KEY (job_id), UNIQUE KEY uq_transfer_jobs_idempotency (created_by,request_method,request_path,idempotency_key), KEY idx_transfer_jobs_idempotency_expiry (idempotency_expires_at), CONSTRAINT fk_transfer_jobs_job FOREIGN KEY (job_id) REFERENCES background_jobs (id) ON DELETE CASCADE, CONSTRAINT fk_transfer_jobs_creator FOREIGN KEY (created_by) REFERENCES users (id), CONSTRAINT chk_transfer_jobs_request_hash CHECK (request_hash REGEXP _ascii'^[a-f0-9]{64}$')) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_as_cs;
